import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{r as i,o as r,c as t,f as n,a as e,b as o,d as l,e as c}from"./app-bc73ed32.js";const s={},h=e("blockquote",null,[e("p",null,"开发指南")],-1),p=c('<p>在这里记录一些个人科研的开发指南</p><h1 id="代码规范与风格" tabindex="-1"><a class="header-anchor" href="#代码规范与风格" aria-hidden="true">#</a> 代码规范与风格</h1><ul><li><a href="/Effective_Research/C_C++">C/C++</a></li></ul><h1 id="复现与迁移" tabindex="-1"><a class="header-anchor" href="#复现与迁移" aria-hidden="true">#</a> 复现与迁移</h1><p>学会使用 <code>docker</code> 或 <code>podman</code> 等容器，我一般使用 <code>docker</code>（目前大部分都还是使用的 <code>docker</code>）</p><h2 id="复现" tabindex="-1"><a class="header-anchor" href="#复现" aria-hidden="true">#</a> 复现</h2><p>复现代码分为：</p><ol><li>拉取开源代码进行实验的复现</li><li>阅读论文手写代码复现，并与实验进行对比</li></ol><h3 id="实验复现" tabindex="-1"><a class="header-anchor" href="#实验复现" aria-hidden="true">#</a> 实验复现</h3><div class="hint-container tip"><p class="hint-container-title">提示</p><p>当前 <code>github</code> 必须要在使用的机器上认证，才能够拉取代码</p></div><p>工作流程如下：</p><ol><li><code>git clone &lt;url&gt;</code> 拉取代码</li><li>阅读 <code>README</code> 或 <code>INSTALL</code> 等文档，一般都会有写如何复现</li><li>如果文件目录中没有看见 <code>Dockerfile</code>，请自己手写一个 <code>Dockerfile</code> 进行复现，否则使用他的</li></ol>',12),_=e("code",null,"Dockerfile",-1),f={href:"https://yeasy.gitbook.io/docker_practice/",target:"_blank",rel:"noopener noreferrer"},u=c('<p>手写时请注意，需要你确定 <code>README</code> 中所提到的包并在 <code>docker</code> 中安装。</p><div class="hint-container danger"><p class="hint-container-title">警告</p><p>请不要在本地进行实验复现，随着复现的实验越来越多，你的本地包环境可能会变得十分杂乱，到最后产生版本不兼任等问题，会浪费很多时间来解决类似这种环境问题。</p></div><h3 id="开发复现" tabindex="-1"><a class="header-anchor" href="#开发复现" aria-hidden="true">#</a> 开发复现</h3><p>在这种情况下，我并不推荐你使用 <code>docker</code> 环境，可以直接在本地进行开发，使用 <code>docker</code> 环境进行测试</p><p>本地的系统最好也是 <code>Linux</code>，这样就可以省去迁移的步骤。如果你使用 <code>Windows</code> ，也那么可以使用 <code>WSL</code> 进行开发。</p><div class="hint-container tip"><p class="hint-container-title">提示</p><p><code>WSL</code> 最好选择与你将要迁移过去的系统一样的发行版（版本可以不一样）</p></div><h2 id="迁移" tabindex="-1"><a class="header-anchor" href="#迁移" aria-hidden="true">#</a> 迁移</h2><p>当你的代码完成后，需要迁移到服务器上跑实验数据，请写 <code>Dockerfile</code> 开一个自己的 <code>docker</code> 来跑数据，不要污染服务器的包环境（并且你可能也并没有 <code>sudo</code> 权限）</p><p>因此，本地验证完正确性后，请将代码的运行环境迁移到服务器的 <code>docker</code> 上，不要污染服务器的包环境。</p>',9);function k(x,m){const d=i("ExternalLinkIcon");return r(),t("div",null,[h,n("more"),p,e("p",null,[o("如何手写 "),_,o("，请看教程 "),e("a",f,[o("Docker实践"),l(d)])]),u])}const E=a(s,[["render",k],["__file","index.html.vue"]]);export{E as default};
